# Issue

**Related**: https://github.com/llvm/circt/issues/6399

In `FIRRTLOps.cpp`, `FModuleLike` has two seemingly similiar operations called `getPorts()` and `getPort(size_t)`. `getPorts()` works reliably, but `getPort(size_t)` can crash `firtool` (and `circt-opt`) with an assertion failure when the port does not have a symbol.

## Reproduction

Given following pass,

```cpp
namespace {
struct GetPortExperimentPass
    : public GetPortExperimentBase<GetPortExperimentPass> {
  void runOnOperation() override {
    CircuitOp circuit = getOperation();
    OpBuilder classBuilder(circuit);
    classBuilder.setInsertionPointToStart(circuit.getBodyBlock());

    ClassOp generatedWithPort =
        createSimpleClassWithPortSym(&circuit, classBuilder);
    printOutClassOpPorts(generatedWithPort);

    ClassOp generatedWithoutPort =
        createSimpleClassWithoutPortSym(&circuit, classBuilder);
    printOutClassOpPorts(generatedWithoutPort);
  }

private:
  void printOutClassOpPorts(ClassOp &generated) {
    LLVM_DEBUG(llvm::dbgs() << "Found ports with getPorts() API: \n");
    for (auto port : generated.getPorts())
      LLVM_DEBUG(llvm::dbgs() << "- " << port.name << "\n");

    LLVM_DEBUG(llvm::dbgs() << "Direct access with getPort(size_t): \n");
    LLVM_DEBUG(llvm::dbgs() << "- " << generated.getPort(0).name << "\n");
    LLVM_DEBUG(llvm::dbgs() << "- " << generated.getPort(1).name << "\n");
  }

  ClassOp createSimpleClassWithoutPortSym(CircuitOp *circuit,
                                          OpBuilder builder) {
    MLIRContext *context = circuit->getContext();

    StringType portType = StringType::get(context);
    PortInfo nameOut(StringAttr::get(context, "name"), portType,
                     Direction::Out);
    PortInfo nameIn(StringAttr::get(context, "nameIn"), portType,
                    Direction::In);
    const SmallVector<PortInfo, 2> instInfoPorts = {nameOut, nameIn};

    ClassOp instInfoClass = builder.create<ClassOp>(
        circuit->getLoc(), StringAttr::get(context, "ClassWithoutPortSym"),
        instInfoPorts);

    // PropAssign is deliberately omitted to minimize the reproduction code.
    return instInfoClass;
  }

  ClassOp createSimpleClassWithPortSym(CircuitOp *circuit, OpBuilder builder) {
    MLIRContext *context = circuit->getContext();

    StringType portType = StringType::get(context);
    StringAttr nameAttr = StringAttr::get(context, "name");
    PortInfo nameOut(nameAttr, portType, Direction::Out, nameAttr);

    StringAttr nameInAttr = StringAttr::get(context, "nameIn");
    PortInfo nameIn(nameInAttr, portType, Direction::In, nameInAttr);
    const SmallVector<PortInfo, 2> instInfoPorts = {nameOut, nameIn};

    ClassOp instInfoClass = builder.create<ClassOp>(
        circuit->getLoc(), StringAttr::get(context, "ClassWithPortSym"),
        instInfoPorts);

    // PropAssign is deliberately omitted to minimize the reproduction code.
    return instInfoClass;
  }
};
} // namespace
```

Using this trivial input:

```
firrtl.circuit "BlankModule" {
    firrtl.module @BlankModule() {}
}
```

The generated IR is

```
module {
  firrtl.circuit "BlankModule" {
    firrtl.class @ClassWithPortSym(out %name: !firrtl.string sym @name, in %nameIn: !firrtl.string sym @nameIn) {
    }
    firrtl.class @ClassWithoutPortSym(out %name: !firrtl.string, in %nameIn: !firrtl.string) {
    }
    firrtl.module @BlankModule() {
    }
  }
}
```

**Behavior**:
- **Without debug option**: No crashes.
- **With debug** (`--debug` or `--debug-only=<pass>`): accessing ports via `getPort(size_t)` on the symbol-less class causes an assertion failure.

```
